// Map item name -> suppliers for quick lookup
export function getSuppliersForItem(itemName: string): string[] {
  const key = itemName.trim().toUpperCase();
  const found = STORE_ITEM_MASTER.find(x => x.item.toUpperCase() === key);
  return found?.suppliers ?? [];
}

// Fuzzy search items by name
export function searchItems(query: string): StoreItemMaster[] {
  if (!query.trim()) return STORE_ITEM_MASTER.slice(0, 50);
  const q = query.trim().toUpperCase();
  return STORE_ITEM_MASTER.filter(x => x.item.toUpperCase().includes(q)).slice(0, 60);
}

// Get all unique supplier names
export function getAllSupplierNames(): string[] {
  return SUPPLIER_MASTER.map(s => s.name);
}

// Get items for a supplier
export function getItemsForSupplier(supplierName: string): string[] {
  const key = supplierName.trim().toUpperCase();
  return STORE_ITEM_MASTER.filter(x => x.suppliers.some(s => s.toUpperCase() === key)).map(x => x.item);
}
